208	#[async_trait]
209	impl ans_core::BrowserBackend for CdpBackend {
210	    async fn navigate(&self, url: &str, timeout: Duration) -> Result<PageState, BrowserError> {
211	        tracing::info!(%url, "Navigating");
212	
213	        let cmd = command::page_navigate(url);
214	        let result = self.connection.send_command(cmd, timeout).await?;
215	        let _nav = command::parse_navigation_result(&result);
216	
217	        // Wait briefly for the page to start loading, then get frame tree
218	        tokio::time::sleep(Duration::from_millis(500)).await;
219	
220	        let frame_tree = self
221	            .connection
222	            .send_command(command::page_get_frame_tree(), timeout)
223	            .await?;
224	        let tree = command::parse_frame_tree(&frame_tree);
225	        let info = command::parse_page_info(&tree);
226	
227	        // Try to get title via JS
228	        let title = self
229	            .connection
230	            .send_command(
231	                command::runtime_evaluate("document.title"),
232	                Duration::from_secs(5),
233	            )
234	            .await
235	            .ok()
236	            .and_then(|v| v.as_str().map(String::from))
237	            .unwrap_or_else(|| info.title.clone());
238	
239	        let dom_nodes = self
240	            .connection
241	            .send_command(
242	                command::runtime_evaluate("document.querySelectorAll('*').length"),
243	                Duration::from_secs(5),
244	            )
245	            .await
246	            .ok()
247	            .and_then(|v| v.as_u64())
248	            .unwrap_or(0);
249	
250	        let visible_text = self
251	            .connection
252	            .send_command(
253	                command::runtime_evaluate("document.body?.innerText?.slice(0, 2000) || ''"),
254	                Duration::from_secs(5),
255	            )
256	            .await
257	            .ok()
258	            .and_then(|v| {
259	                v.as_str().map(|s| {
260	                    s.lines()
261	                        .filter(|l| !l.trim().is_empty())
262	                        .map(String::from)
263	                        .take(50)
264	                        .collect::<Vec<_>>()
265	                })
266	            })
267	            .unwrap_or_default();
268	
269	        *self.current_url.lock().await = info.url.clone();
270	
271	        Ok(PageState {
272	            url: info.url,
273	            title,
274	            loaded: info.loaded,
275	            dom_node_count: dom_nodes,
276	            visible_text,
277	            timestamp: chrono::Utc::now(),
278	        })
279	    }
280	
281	    async fn get_distilled_dom(&self, mode: DistillMode) -> Result<DistilledPage, BrowserError> {
282	        let doc_result = self
283	            .connection
284	            .send_command(command::dom_get_document(-1), Duration::from_secs(10))
285	            .await?;
286	
287	        let title = self
288	            .connection
289	            .send_command(
290	                command::runtime_evaluate("document.title"),
291	                Duration::from_secs(3),
292	            )
293	            .await
294	            .ok()
295	            .and_then(|v| v.as_str().map(String::from))
296	            .unwrap_or_default();
297	
298	        let url = self.current_url.lock().await.clone();
299	        let distiller = ans_distill::Distiller;
300	        Ok(distiller.process(&doc_result, mode, &url, &title))
301	    }
302	
303	    async fn capture_screenshot(
304	        &self,
305	        format: ImageFormat,
306	        full_page: bool,
307	    ) -> Result<Vec<u8>, BrowserError> {
308	        let (fmt_str, quality) = match format {
309	            ImageFormat::Png => ("png", None),
310	            ImageFormat::Jpeg { quality } => ("jpeg", Some(quality)),
311	        };
312	
313	        let mut params = serde_json::json!({ "format": fmt_str });
314	        if let Some(q) = quality {
315	            params["quality"] = serde_json::json!(q);
316	        }
317	        if full_page {
318	            params["captureBeyondViewport"] = serde_json::json!(true);
319	        }
320	
321	        let cmd = CdpCommand::new("Page.captureScreenshot", params);
322	        let result = self
323	            .connection
324	            .send_command(cmd, Duration::from_secs(15))
325	            .await?;
326	
327	        command::parse_screenshot_result(&result)
328	            .map_err(|e| BrowserError::CdpProtocol(e.to_string()))
329	    }
330	
331	    async fn click(&self, selector: &str) -> Result<ActionOutcome, BrowserError> {
332	        let start = std::time::Instant::now();
333	
334	        // 1. Get document root
335	        let doc_result = self
336	            .connection
337	            .send_command(command::dom_get_document(0), Duration::from_secs(5))
338	            .await?;
339	        let root_id = command::parse_dom_node_id(&doc_result)
340	            .map_err(|e| BrowserError::CdpProtocol(e.to_string()))?;
341	
342	        // 2. Query selector
343	        let qs_result = self
344	            .connection
345	            .send_command(
346	                command::dom_query_selector(root_id, selector),
347	                Duration::from_secs(5),
348	            )
349	            .await
350	            .map_err(|e| {
351	                if matches!(e, BrowserError::CdpProtocol(_)) {
352	                    BrowserError::SelectorNotFound(selector.to_string())
353	                } else {
354	                    e
355	                }
356	            })?;
357	
358	        let node_id = command::parse_query_selector_result(&qs_result)
359	            .map_err(|_| BrowserError::SelectorNotFound(selector.to_string()))?;
360	
361	        // 3. Get box model for coordinates
362	        let box_result = self
363	            .connection
364	            .send_command(command::dom_get_box_model(node_id), Duration::from_secs(5))
365	            .await?;
366	        let box_model = command::parse_box_model(&box_result)
367	            .map_err(|_| BrowserError::NotInteractable(selector.to_string()))?;
368	
369	        let mut center_x = box_model.x + box_model.width / 2.0;
370	        let mut center_y = box_model.y + box_model.height / 2.0;
371	
372	        // Humanized: slight random offset from exact center + pre-click delay
373	        let humanize = self.stealth.as_ref().is_some_and(|s| s.humanize);
374	        if humanize {
375	            use ans_stealth::humanize;
376	            center_x += ans_stealth::humanize::position_jitter();
377	            center_y += ans_stealth::humanize::position_jitter();
378	            tokio::time::sleep(humanize::click_linger()).await;
379	        }
380	
381	        // 4. Scroll element into view
382	        let _ = self
383	            .connection
384	            .send_command(
385	                command::dom_scroll_into_view(node_id),
386	                Duration::from_secs(5),
387	            )
388	            .await;
389	
390	        // Brief delay for scroll animation
391	        tokio::time::sleep(Duration::from_millis(100)).await;
392	
393	        // 5. Dispatch mouse events
394	        if humanize {
395	            // Seek to element with movement, then press/release
396	            self.send_ignore(command::input_dispatch_mouse_event(
397	                "mouseMoved",
398	                center_x,
399	                center_y,
400	                "none",
401	            ))
402	            .await;
403	            tokio::time::sleep(Duration::from_millis(20)).await;
404	        }
405	
406	        self.send_ignore(command::input_dispatch_mouse_event(
407	            "mousePressed",
408	            center_x,
409	            center_y,
410	            "left",
411	        ))
412	        .await;
413	        tokio::time::sleep(Duration::from_millis(
414	            if humanize { 60 } else { 50 },
415	        ))
416	        .await;
417	        self.send_ignore(command::input_dispatch_mouse_event(
418	            "mouseReleased",
419	            center_x,
420	            center_y,
421	            "left",
422	        ))
423	        .await;
424	
425	        let elapsed = start.elapsed();
426	
427	        Ok(ActionOutcome {
428	            success: true,
429	            error_message: None,
430	            execution_time_ms: elapsed.as_millis() as u64,
431	            page_url_after: Some(self.current_url.lock().await.clone()),
432	            dom_changed: true,
433	        })
434	    }
