436	    async fn type_text(&self, selector: &str, text: &str) -> Result<ActionOutcome, BrowserError> {
437	        let start = std::time::Instant::now();
438	
439	        // Click the element first to focus it
440	        let _ = self.click(selector).await;
441	
442	        // Humanized: type character-by-character with variable delays
443	        let humanize = self.stealth.as_ref().is_some_and(|s| s.humanize);
444	        if humanize {
445	            use ans_stealth::humanize;
446	            for (i, c) in text.chars().enumerate() {
447	                let ch = c.to_string();
448	                self.send_ignore(command::input_insert_text(&ch)).await;
449	                tokio::time::sleep(humanize::typing_delay(c, i)).await;
450	            }
451	        } else {
452	            self.send_ignore(command::input_insert_text(text)).await;
453	        }
454	
455	        let elapsed = start.elapsed();
456	
457	        Ok(ActionOutcome {
458	            success: true,
459	            error_message: None,
460	            execution_time_ms: elapsed.as_millis() as u64,
461	            page_url_after: Some(self.current_url.lock().await.clone()),
462	            dom_changed: true,
463	        })
464	    }
465	
466	    async fn select_option(
467	        &self,
468	        selector: &str,
469	        value: &str,
470	    ) -> Result<ActionOutcome, BrowserError> {
471	        let start = std::time::Instant::now();
472	
473	        // Use JS to set the select value and dispatch a change event
474	        let script = format!(
475	            r"
476	            (function() {{
477	                var el = document.querySelector('{}');
478	                if (!el) return 'selector not found';
479	                el.value = '{}';
480	                el.dispatchEvent(new Event('change', {{ bubbles: true }}));
481	                return 'ok';
482	            }})()
483	            ",
484	            escape_js_string(selector),
485	            escape_js_string(value),
486	        );
487	
488	        let cmd = command::runtime_evaluate(&script);
489	        let result = self
490	            .connection
491	            .send_command(cmd, Duration::from_secs(5))
492	            .await?;
493	        let eval_result = command::parse_evaluate_result(&result)
494	            .map_err(|e| BrowserError::CdpProtocol(e.to_string()))?;
495	
496	        let success = eval_result.as_str() == Some("ok");
497	        let elapsed = start.elapsed();
498	
499	        Ok(ActionOutcome {
500	            success,
501	            error_message: if success {
502	                None
503	            } else {
504	                eval_result.as_str().map(String::from)
505	            },
506	            execution_time_ms: elapsed.as_millis() as u64,
507	            page_url_after: Some(self.current_url.lock().await.clone()),
508	            dom_changed: true,
509	        })
510	    }
511	
512	    async fn scroll(
513	        &self,
514	        pixels: Option<i32>,
515	        selector: Option<&str>,
516	    ) -> Result<ActionOutcome, BrowserError> {
517	        let start = std::time::Instant::now();
518	
519	        let script = if let Some(sel) = selector {
520	            format!(
521	                "document.querySelector('{}')?.scrollIntoView({{ behavior: 'instant', block: 'center' }});",
522	                escape_js_string(sel)
523	            )
524	        } else if let Some(px) = pixels {
525	            format!("window.scrollBy(0, {px});")
526	        } else {
527	            "window.scrollBy(0, 300);".to_string()
528	        };
529	
530	        let cmd = command::runtime_evaluate(&script);
531	        let _ = self
532	            .connection
533	            .send_command(cmd, Duration::from_secs(5))
534	            .await;
535	
536	        let elapsed = start.elapsed();
537	
538	        Ok(ActionOutcome {
539	            success: true,
540	            error_message: None,
541	            execution_time_ms: elapsed.as_millis() as u64,
542	            page_url_after: Some(self.current_url.lock().await.clone()),
543	            dom_changed: false,
544	        })
545	    }
546	
547	    async fn wait_for_load(&self, timeout: Duration) -> Result<PageState, BrowserError> {
548	        // Poll document.readyState until complete or timeout
549	        let start = std::time::Instant::now();
550	        loop {
551	            let cmd = command::runtime_evaluate("document.readyState");
552	            if let Ok(result) = self
553	                .connection
554	                .send_command(cmd, Duration::from_secs(3))
555	                .await
556	            {
557	                if let Ok(val) = command::parse_evaluate_result(&result) {
558	                    if val.as_str() == Some("complete") {
559	                        break;
560	                    }
561	                }
562	            }
563	
564	            if start.elapsed() > timeout {
565	                return Err(BrowserError::NavigationTimeout(timeout));
566	            }
567	            tokio::time::sleep(Duration::from_millis(200)).await;
568	        }
569	
570	        let current_url = self.current_url.lock().await.clone();
571	        Ok(PageState {
572	            url: current_url,
573	            title: String::new(),
574	            loaded: true,
575	            dom_node_count: 0,
576	            visible_text: vec![],
577	            timestamp: chrono::Utc::now(),
578	        })
579	    }
580	
581	    async fn execute_script(&self, script: &str) -> Result<String, BrowserError> {
582	        let cmd = command::runtime_evaluate(script);
583	        let result = self
584	            .connection
585	            .send_command(cmd, Duration::from_secs(10))
586	            .await?;
587	        let val = command::parse_evaluate_result(&result)
588	            .map_err(|e| BrowserError::CdpProtocol(e.to_string()))?;
589	        Ok(val.to_string())
590	    }
591	
592	    async fn close(&self) -> Result<(), BrowserError> {
593	        tracing::info!("Closing CDP backend");
594	        // The Chromium process is killed on drop, but we also close
595	        // the WebSocket gracefully by dropping the sender.
596	        // Process cleanup happens in ChromiumProcess::drop.
597	        Ok(())
598	    }
599	}
