454	    async fn update_goal_progress(
455	        &self,
456	        request: Request<ProgressUpdate>,
457	    ) -> Result<Response<GoalState>, Status> {
458	        let req = request.into_inner();
459	        let goal_id = Uuid::parse_str(&req.goal_id)
460	            .map_err(|_| Status::invalid_argument("invalid goal_id"))?;
461	
462	        let status = ans_goal::serialization::str_to_goal_status(&req.status);
463	
464	        // If Python sent LLM-decomposed sub-goals, replace them
465	        if !req.sub_goals.is_empty() {
466	            let sub_goals: Vec<ans_core::goal::SubGoal> = req
467	                .sub_goals
468	                .iter()
469	                .map(ans_goal::serialization::proto_to_sub_goal)
470	                .collect();
471	            let _ = self.goals.update_sub_goals(goal_id, sub_goals);
472	        }
473	
474	        let state = self
475	            .goals
476	            .update_progress(goal_id, req.progress, status)
477	            .map_err(|e| match e {
478	                ans_goal::GoalStoreError::NotFound(id) => {
479	                    Status::not_found(format!("goal {id} not found"))
480	                }
481	                other => Status::internal(other.to_string()),
482	            })?;
483	
484	        Ok(Response::new(ans_goal::serialization::goal_state_to_proto(
485	            &state,
