489	    type SubscribeGoalUpdatesStream = std::pin::Pin<
490	        Box<
491	            dyn tonic::codegen::tokio_stream::Stream<
492	                    Item = std::result::Result<ans_proto::ans::GoalUpdate, tonic::Status>,
493	                > + std::marker::Send,
494	        >,
