497	    async fn subscribe_goal_updates(
498	        &self,
499	        request: Request<GoalStateRequest>,
500	    ) -> Result<Response<Self::SubscribeGoalUpdatesStream>, Status> {
501	        let req = request.into_inner();
502	        let goal_id = if req.goal_id.is_empty() {
503	            None
504	        } else {
505	            Some(
506	                Uuid::parse_str(&req.goal_id)
507	                    .map_err(|_| Status::invalid_argument("invalid goal_id"))?,
508	            )
509	        };
510	
511	        let rx = self.goals.subscribe();
512	        let stream = BroadcastStream::new(rx).filter_map(move |result| {
513	            let gid = goal_id;
514	            let notification = result.ok()?;
515	            if gid.is_none_or(|id| notification.goal_id == id) {
516	                Some(Ok(ans_proto::ans::GoalUpdate {
517	                    goal_id: notification.goal_id.to_string(),
518	                    event_type: goal_status_event(notification.status),
519	                    message: notification.message,
520	                    progress: notification.progress,
521	                    sub_goal: None,
522	                }))
523	            } else {
524	                None
525	            }
526	        });
527	
528	        Ok(Response::new(Box::pin(stream)))
529	    }
